it('runs multiple cycles and stops when aborted on second cycle', async () => {
    const session = makeSession('x');
    let cycle = 0;
    const result = await runAgentAICycleStub(session, {
        onStream: async (s) => {
            cycle++;
            if (cycle === 2) s.aborted = true;
            return cycle < 3 ? [{ id: `t${cycle}` }] : [];
        }
    });
    // Cycle 1 streams, cycle 2 detects abort at entry (cycleDepth already 1)
    expect(result).toBe('early-exit:entry');
    expect(session.cycleDepth).toBe(1);     // only first cycle counted
});

tool_input.new_string:
it('runs multiple cycles and stops when aborted during second cycle stream', async () => {
    const session = makeSession('x');
    let cycle = 0;
    const result = await runAgentAICycleStub(session, {
        onStream: async (s) => {
            cycle++;
            if (cycle === 2) s.aborted = true;  // abort fires mid-stream on cycle 2
            return [{ id: `t${cycle}` }];        // always return a tool call
        }
    });
    // Cycle 1 finishes stream + tools + recurse; cycle 2 stream sets aborted,
    // then the pre-tools guard fires before tools execute.
    expect(result).toBe('early-exit:pre-tools');
    expect(session.cycleDepth).toBe(1);     // only first cycle incremented
});

